const input = $json;
const headers = input.headers || {};
const body = input.body || input;
const internal = headers['x-jarvis-internal'] || headers['X-JARVIS-INTERNAL'];
const expectedToken = typeof $vars !== 'undefined' ? $vars.JARVIS_TOKEN : '';
const parameters = body.parameters || {};
const startedAt = Date.now();
const validDate = /^\d{4}-\d{2}-\d{2}$/.test(parameters.centralDate || '');
const validWindow = !Number.isNaN(Date.parse(parameters.since || '')) && !Number.isNaN(Date.parse(parameters.until || ''));
const authorized = Boolean(expectedToken && internal === expectedToken);
const valid = authorized && body.tool === 'ava.context.refresh' && validDate && validWindow;
return [{ json: { valid, authorized, parameters, requestId: body.requestId, startedAt, error: !authorized ? 'Unauthorized executor request' : body.tool !== 'ava.context.refresh' ? 'Invalid Ava context tool' : !validDate || !validWindow ? 'Missing or invalid Central date window' : null } }];

const items = $input.all().map(item => item.json);
const failed = items.find(item => item.error || item.statusCode >= 400);
const first = items[0] || {};
const tasks = Array.isArray(first.results) ? first.results : Array.isArray(first.tasks) ? first.tasks : Array.isArray(first.items) ? first.items : failed ? [] : items;
return [{ json: { source: 'todoist:tasks', ok: !failed, data: tasks, error: failed ? String(failed.error?.message || failed.message || 'Todoist open-task read failed') : null } }];

const items = $input.all().map(item => item.json);
const failed = items.find(item => item.error || item.statusCode >= 400);
const first = items[0] || {};
const data = Array.isArray(first.items) || Array.isArray(first.results) || Array.isArray(first.tasks) ? first : { items };
return [{ json: { source: 'todoist:completed', ok: !failed, data: failed ? { items: [] } : data, error: failed ? String(failed.error?.message || failed.message || 'Todoist completed-task read failed') : null } }];

const items = $input.all().map(item => item.json);
const failed = items.find(item => item.error || item.statusCode >= 400);
return [{ json: { source: 'gmail:chill-tech', ok: !failed, data: failed ? [] : items, error: failed ? String(failed.error?.message || failed.message || 'CHILL TECH Gmail read failed') : null } }];

const items = $input.all().map(item => item.json);
const failed = items.find(item => item.error || item.statusCode >= 400);
return [{ json: { source: 'gmail:idad', ok: !failed, data: failed ? [] : items, error: failed ? String(failed.error?.message || failed.message || 'IDAD Gmail read failed') : null } }];

const validation = $('Validate Batch Request').first().json;
const tasks = $('Pack Todoist Tasks').first().json;
const completed = $('Pack Todoist Completed').first().json;
const chill = $('Pack Gmail CHILL TECH').first().json;
const idad = $('Pack Gmail IDAD').first().json;
const sources = [tasks, completed, chill, idad];
const sourceFailures = sources.filter(source => !source.ok).map(source => source.source);
return [{ json: { success: true, tool: 'ava.context.refresh', timestamp: new Date().toISOString(), data: { todoist: { tasks: tasks.data, completed: completed.data }, gmail: { 'chill-tech': chill.data, idad: idad.data }, sourceFailures, sourceStatus: Object.fromEntries(sources.map(source => [source.source, { ok: source.ok, error: source.error }])) }, requestId: validation.requestId, durationMs: Date.now() - validation.startedAt, adapter: 'n8n-ava-context-batch' } }];
